  'person',
  '{"document_kind":"tour_product_full_page_v1","schema_version":1,"slug":"east-jeju-classic-bus-tour","locale":"ko","product_id":"east-jeju-classic-bus-tour","seo":{"pageTitle":"East Jeju Sunrise Peak, Folk Village & Hamdeok Bus Day Tour | AtoC Korea","metaDescription":"A classic East Jeju bus day tour covering Ilchul Land, Seongeup Folk Village, Seongsan Ilchulbong, the Haenyeo Show, and Hamdeok Beach. A strong first-time route for travelers who want Jeju’s iconic east-side nature and culture in one day."},"catalog_card":{"slug":"east-jeju-classic-bus-tour","title":"East Jeju Sunrise Peak, Folk Village & Hamdeok Bus Day Tour","subtitle":"Lava cave atmosphere, living village culture, UNESCO scenery, haenyeo heritage, and a signature beach in one classic east-side route, now with one hour of free lunch time near Seongsan.","region":"East Jeju","duration":"10 hours","stopsCount":6,"rating":4.8,"reviewCount":112,"badges":["Best-Value Bus Tour","Classic East Jeju Route","First-Time Friendly"],"heroImage":"https://api.cdn.visitjeju.net/photomng/imgpath/202409/20/c8bf6191-832c-4605-a948-96f07f6112d2.webp","thumbnail":"https://api.cdn.visitjeju.net/photomng/thumbnailpath/202409/20/b9661064-af2f-4197-aef0-d3d44bf6c2b5.webp","priceLabel":"From US$49 per person","shortCardDescription":"A full-day East Jeju bus route that links cave scenery, traditional village culture, Seongsan Ilchulbong, living haenyeo heritage, and Hamdeok Beach, with one hour of free lunch time added near Seongsan. It is built for travelers who want strong iconic coverage with a lower price barrier."},"headlineLine1":"East Jeju Sunrise Peak, Folk Village","headlineLine2":"and Hamdeok Bus Day Tour","price":{"amountLabel":"49","currency":"USD","per":"person"},"hero":{"imageUrl":"https://api.cdn.visitjeju.net/photomng/imgpath/202409/20/c8bf6191-832c-4605-a948-96f07f6112d2.webp","imagePosition":"center 52%","tagline":"From lava-cave atmosphere and a living folk village to UNESCO coastal scenery, Jeju haenyeo culture, and Hamdeok’s clear water, this classic East Jeju bus route delivers iconic variety at a practical price point, with one hour of free lunch time included near Seongsan.","pills":["Classic East Jeju","Bus Day Tour","Best Value"],"meta":{"duration":"10 hours","region":"East Jeju","stops":"6 stops","rating":4.8,"ratingStars":5}},"subnavItems":[{"id":"overview","label":"Overview"},{"id":"itinerary","label":"Itinerary"},{"id":"details","label":"Details"},{"id":"faq","label":"FAQ"},{"id":"reviews","label":"Reviews"}],"glanceItems":[{"icon":"camera","label":"Photo Potential","value":"Very High"},{"icon":"mountain","label":"Scenery Density","value":"High"},{"icon":"footprints","label":"Walking Difficulty","value":"Moderate"},{"icon":"cloud-rain","label":"Rain Suitability","value":"Moderate"},{"icon":"users","label":"Family Suitability","value":"Good"},{"icon":"gauge","label":"Pace","value":"Full but Comfortable"}],"galleryItems":[{"id":1,"type":"photo","src":"https://api.cdn.visitjeju.net/photomng/imgpath/202409/20/c8bf6191-832c-4605-a948-96f07f6112d2.webp","location":"Seongsan Ilchulbong","atmosphere":"The day''s signature UNESCO landmark and strongest iconic view","alt":"Seongsan Ilchulbong rising above the East Jeju coast"},{"id":2,"type":"photo","src":"https://api.cdn.visitjeju.net/photomng/imgpath/202207/14/47bdc32f-cb51-4de3-8239-06299643b485.webp","location":"Ilchul Land / Micheongul Cave","atmosphere":"A cooler lava-cave opening with indoor value and unusual texture","alt":"Micheongul Cave inside Ilchul Land in East Jeju"},{"id":3,"type":"photo","src":"https://api.cdn.visitjeju.net/photomng/imgpath/202409/06/cf7e9f6b-178f-4d3d-b978-91beb5145a10.webp","location":"Seongeup Folk Village","atmosphere":"Living heritage and old Jeju village character","alt":"Traditional houses at Seongeup Folk Village in Jeju"},{"id":4,"type":"photo","src":"https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=1200&q=80","location":"Hamdeok Beach","atmosphere":"A bright, relaxed finish with Jeju''s signature clear water feeling","alt":"Bright coastal atmosphere inspired by Hamdeok Beach in Jeju"}],"itineraryStops":[{"number":1,"time":"09:50","duration":"60 min","name":"Ilchul Land","category":"Garden and Lava Cave Stop","description":"Ilchul Land works well as an opening stop because it combines easy garden circulation with the cooler Micheongul lava-cave section. It gives the day an early indoor-outdoor balance before the route moves deeper into East Jeju''s cultural and coastal landmarks.","image":"https://api.cdn.visitjeju.net/photomng/imgpath/202207/14/47bdc32f-cb51-4de3-8239-06299643b485.webp","highlights":["A flexible first stop with both outdoor paths and cave atmosphere","Useful early rain-buffer compared with a fully exposed route opening","Good variety for mixed-age groups","A different visual tone from the coast-heavy second half"],"timeUsed":["Arrival briefing and entry","Garden walk and Micheongul cave viewing","Regroup and depart"],"whyOnRoute":"Starting here gives the route a softer operational opening and improves weather resilience before the village, UNESCO climb, and exposed coastline sections.","visitBasics":{"hours":"08:30–19:00 / Micheongul cave admission generally until 1 hour before sunset","closed":"Open year-round","admission":"Commonly ticketed attraction; keep live pricing aligned with current checkout setup","walking":"Easy"},"convenience":{"restroom":"Available on site","parking":"Parking available"},"smartNotes":{"photo":"The cave textures and garden framing work better than rushed single-point photos, so this stop benefits from steady pacing.","facilities":"Facilities are stronger here than at most pure viewpoint stops.","tip":"This is one of the route''s best buffers when wind or light rain makes later outdoor stops less comfortable."}},{"number":2,"time":"11:05","duration":"40 min","name":"Seongeup Folk Village","category":"Living Heritage Village","description":"Seongeup adds cultural depth that many scenic-only routes miss. Because it is a living village rather than a staged set, the stop gives travelers a clearer sense of old Jeju homes, stone walls, and daily life traditions.","image":"https://api.cdn.visitjeju.net/photomng/imgpath/202409/06/cf7e9f6b-178f-4d3d-b978-91beb5145a10.webp","highlights":["One of East Jeju''s strongest culture-focused stops","A living village with real local heritage value","Adds storytelling depth between nature landmarks","Works well for first-time visitors who want more than scenery alone"],"timeUsed":["Village orientation and short guided walk","Free look-around and photo time","Regroup and depart"],"whyOnRoute":"It breaks up the nature-heavy flow and adds heritage context before the route turns toward Seongsan and the coast.","visitBasics":{"hours":"Open village environment; access patterns can vary by site area and local operation","closed":"Open year-round","admission":"Generally free to enter the village area, though some shops or experiences may be optional","walking":"Easy to moderate"},"convenience":{"restroom":"Available in or near visitor areas","parking":"Parking available"},"smartNotes":{"photo":"Stone walls, thatched roofs, and side-lane composition usually read better than wide rushed overview shots.","facilities":"This is a cultural walk stop rather than a large modern complex.","tip":"Keep the stop focused on village character and guide context rather than overextending shopping time."}},{"number":3,"time":"12:10","duration":"70 min","name":"Seongsan Ilchulbong","category":"UNESCO Tuff Cone Landmark","description":"Seongsan Ilchulbong is the route''s most iconic landmark and one of Jeju''s strongest first-time stops. The summit trail is short in distance but clearly steep, so the stop feels more active than most bus-tour landmarks.","image":"https://api.cdn.visitjeju.net/photomng/imgpath/202409/20/c8bf6191-832c-4605-a948-96f07f6112d2.webp","highlights":["UNESCO World Natural Heritage site and one of Jeju''s signature views","High payoff for first-time visitors","Short but steep summit climb with strong visual reward","A landmark that anchors the whole route"],"timeUsed":["Entry and trail briefing","Ascent or lower-area sightseeing depending on pace and condition","Regroup and depart"],"whyOnRoute":"This is the natural centerpiece of an East Jeju classic route, so it works best near midday when visibility is often still stable and the day''s momentum is high.","visitBasics":{"hours":"Seasonal operation; for example, Nov–Feb 00:00–18:00, Mar–Apr & Sep–Oct 05:00–19:00, May–Aug 04:30–20:00, with ticketing ending earlier","closed":"First Monday of each month, or the following day if Monday is a public holiday","admission":"Ticketed summit section; keep live pricing aligned with current checkout setup","walking":"Moderate to difficult if climbing to the top"},"convenience":{"restroom":"Available near the entrance area","parking":"Parking available"},"smartNotes":{"photo":"Wide crater-and-sea framing is usually the strongest visual payoff.","facilities":"This is a major landmark stop with solid basic visitor support.","tip":"Not every traveler needs to do the full summit climb; the lower-area coastal section can still work for guests avoiding heavier stairs."}},{"number":4,"time":"13:25","duration":"60 min","name":"Lunch Break (Free Choice)","category":"Meal break","description":"Enjoy one hour of free lunch time near Seongsan. This flexible meal break lets travelers choose a restaurant that fits their taste and pace before continuing to the haenyeo segment.","image":"https://images.unsplash.com/photo-1551218808-94e220e084d2?w=1200&q=80&fm=jpg","highlights":["One full hour for lunch","Free-choice meal stop","Placed after Seongsan climbing time","Better pacing before the afternoon program"],"timeUsed":["Lunch","Restroom break","Seat reset before departure"],"whyOnRoute":"This break sits naturally after the Seongsan stop, where many travelers want time to recover from the climb and eat before the afternoon coastal segment.","visitBasics":{"hours":"Depends on restaurant","closed":"Varies by venue","admission":"Meal cost not included","walking":"Low"},"convenience":{"restroom":"Available at nearby restaurants","parking":"Bus-accessible nearby"},"smartNotes":{"photo":"Not a photo-focused stop","facilities":"Restaurant options vary by day and traffic flow","tip":"A simple local meal works best if you want a relaxed pace."}},{"number":5,"time":"15:00","duration":"40 min","name":"Haenyeo Show","category":"Living Coastal Culture Performance","description":"The haenyeo stop adds something few Jeju routes can match: living culture happening on the coast rather than inside a display panel. Because the performance is weather-sensitive, the tour should treat it as a priority highlight with a clear fallback plan.","image":"https://images.unsplash.com/photo-1544551763-46a013bb70d5?w=1200&q=80","highlights":["One of the best ways to connect Jeju sightseeing with living local culture","Stronger storytelling value than a standard photo stop","Directly tied to Jeju''s haenyeo heritage","Memorable when sea conditions allow normal operation"],"timeUsed":["Move to the viewing area and guide context","Observe the performance if operating normally","If cancelled for weather, replace with Jeju Haenyeo Museum"],"whyOnRoute":"Positioning this after Seongsan keeps the coastal storytelling connected and makes the cultural flow feel natural rather than inserted.","visitBasics":{"hours":"Planned around the 14:00 show window on this product; actual operation is subject to season and weather conditions","closed":"May be cancelled or adjusted in rough sea or poor weather","admission":"Usually viewed without a major ticket barrier, but keep live setup aligned with operations","walking":"Easy"},"convenience":{"restroom":"Basic facilities vary by viewing point and nearby shops","parking":"Operational drop-off and parking depend on day-of traffic"},"smartNotes":{"photo":"Use wider framing and avoid expecting a perfectly fixed stage environment.","facilities":"This is a live coastal viewing stop, so comfort is more weather-dependent than at museums or indoor sites.","tip":"If the show is cancelled, the Jeju Haenyeo Museum is the cleanest substitution because it preserves the route''s cultural logic."}},{"number":6,"time":"16:25","duration":"45 min","name":"Hamdeok Beach","category":"Signature Beach Walk","description":"Hamdeok gives the day a bright, easy finish. After the more structured stops at Seongeup, Seongsan, and the haenyeo segment, the white sand and clear water create a simpler closing mood that many travelers find refreshing.","image":"https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=1200&q=80","highlights":["One of Jeju''s best-known beaches","Clear water and easy seafront walking","A relaxed visual finish after a fuller sightseeing day","Good family and couple appeal"],"timeUsed":["Beachfront orientation and free walk","Photos and short break time","Regroup for return to Jeju City"],"whyOnRoute":"It works naturally as a late-day decompression stop before the return drive to Jeju City.","visitBasics":{"hours":"Open 24 hours","closed":"Open year-round","admission":"Free","walking":"Easy"},"convenience":{"restroom":"Available in the beach area","parking":"Parking available nearby"},"smartNotes":{"photo":"The water color reads best in wider beach shots and side angles rather than tight front-on framing.","facilities":"Amenities and surrounding cafés are part of why this stop feels easy and finish-friendly.","tip":"In strong wind or rough weather, reduce expectations for a long beach stay and keep the stop focused."}}],"routeFlowStops":[{"id":"ilchul-land","name":"Ilchul Land","theme":"Cave + garden opening"},{"id":"seongeup","name":"Seongeup Folk Village","theme":"Living heritage"},{"id":"seongsan","name":"Seongsan Ilchulbong","theme":"UNESCO landmark"},{"id":"lunch-seongsan","name":"Lunch Break (Free Choice)","theme":"Flexible midday reset"},{"id":"haenyeo","name":"Haenyeo Show / Museum fallback","theme":"Coastal culture"},{"id":"hamdeok","name":"Hamdeok Beach","theme":"Relaxed coastal finish"}],"routePhases":[{"label":"Soft Opening","range":"1","theme":"Indoor-outdoor balance","bgClass":"bg-emerald-50/80","textClass":"text-emerald-700","dotClass":"bg-emerald-500"},{"label":"Culture Build","range":"2","theme":"Old Jeju context","bgClass":"bg-amber-50/80","textClass":"text-amber-700","dotClass":"bg-amber-500"},{"label":"Iconic Peak","range":"3","theme":"UNESCO scenery","bgClass":"bg-sky-50/80","textClass":"text-sky-700","dotClass":"bg-sky-500"},{"label":"Lunch Reset","range":"4","theme":"Free-choice meal break","bgClass":"bg-orange-50/80","textClass":"text-orange-700","dotClass":"bg-orange-500"},{"label":"Living Heritage","range":"5","theme":"Haenyeo culture","bgClass":"bg-violet-50/80","textClass":"text-violet-700","dotClass":"bg-violet-500"},{"label":"Light Finish","range":"6","theme":"Beach reset","bgClass":"bg-cyan-50/80","textClass":"text-cyan-700","dotClass":"bg-cyan-500"}],"routeShapeIntro":{"title":"Why this East Jeju route feels balanced","subtitle":"It opens with flexible cave-and-garden pacing, adds real heritage context, peaks with Seongsan, pauses for one hour of free lunch time, carries that story into the haenyeo segment, and finishes with a light beach stop before the return to Jeju City."},"whyTourWorks":{"bestFor":["First-time visitors to Jeju","Travelers who want iconic East Jeju coverage","Couples","Adult families","Visitors who want both natural landmarks and cultural context in one day"],"lessIdeal":["Travelers avoiding stairs or uphill walking","Families relying heavily on strollers","Travelers who want a very slow luxury pace","Anyone seeking a mostly indoor or fully weather-proof route"],"routeLogicSections":[{"title":"Why this bus route works well","icon":"bus","iconBg":"bg-sky-50/80","iconColor":"text-sky-600","items":[{"label":"High iconic coverage for the price","detail":"It connects one of Jeju''s strongest UNESCO landmarks with heritage, living culture, and a signature beach without the price jump of a private format."},{"label":"The route does not feel one-note","detail":"Cave atmosphere, village heritage, summit scenery, haenyeo culture, and beach time each give the day a clearly different mood."},{"label":"The finish gets easier, not harder","detail":"After the active Seongsan segment, the haenyeo stop and Hamdeok finish help the day land more comfortably."}]},{"title":"How the walking load actually feels","icon":"footprints","iconBg":"bg-amber-50/80","iconColor":"text-amber-600","items":[{"label":"Mostly manageable, with one clearly demanding stop","detail":"Ilchul Land, Seongeup, the haenyeo stop, and Hamdeok are manageable for most travelers, while Seongsan Ilchulbong is the one stop that adds real stairs and incline."},{"label":"More active than a pure panorama bus route","detail":"The route stays within normal day-tour range, but it is not a purely passive coach sightseeing day because of Seongsan."},{"label":"Mixed-age groups can usually handle it","detail":"The route works for many mixed-age groups as long as they are comfortable either climbing Seongsan or using the lower-area option."}]},{"title":"When weather changes on site","icon":"cloud-rain","iconBg":"bg-slate-50/80","iconColor":"text-slate-600","items":[{"label":"The route is more resilient than a fully exposed east-coast plan","detail":"Ilchul Land gives useful indoor-outdoor flexibility at the start, and the Jeju Haenyeo Museum is a clean cultural fallback if the live show is cancelled."},{"label":"Seongsan and Hamdeok remain weather-sensitive","detail":"Wind, rain, and visibility changes most strongly affect the UNESCO climb and beach finish."},{"label":"Operational substitutions should preserve the story","detail":"If weather forces a change, the best adjustment is not random replacement but keeping the East Jeju culture-and-coast logic intact."}]}]},"practicalAccordionItems":[{"id":"pickup","title":"Pickup and Return Times","preview":"4 fixed pickup points + 5 city drop-off points","content":["Pickup: 08:30 Ocean Suites Hotel","Pickup: 08:45 Jeju Airport, 3rd Floor Gate 3","Pickup: 08:55 Lotte City Hotel Jeju","Pickup: 09:05 Shilla Duty Free Shop","Drop-off: Ocean Suites Hotel","Drop-off: Jeju Airport, 3rd Floor Gate 3","Drop-off: Lotte City Hotel Jeju","Drop-off: Shilla Duty Free Shop","Extra drop-off available at Dongmun Market","Expected return to Jeju City around 17:40–18:20 depending on traffic, weather, and show operation","Please arrive at least 10 minutes early at your selected pickup point"]},{"id":"walking","title":"Walking and Terrain","preview":"Moderate overall, with Seongsan as the key active stop","content":["Ilchul Land, Seongeup Folk Village, the haenyeo stop, and Hamdeok are generally manageable for most travelers","Seongsan Ilchulbong is the most physically demanding stop because of stairs and uphill sections","If needed, some travelers can limit themselves to the lower area at Seongsan instead of pushing to the summit","Comfortable walking shoes with grip are strongly recommended"]},{"id":"weather","title":"Weather and Route Adjustments","preview":"Most affected by wind at Seongsan, the haenyeo stop, and Hamdeok","content":["Light rain: the tour usually still operates","Heavy rain, rough sea, or strong wind: the haenyeo show may be cancelled and replaced with Jeju Haenyeo Museum","Seongsan Ilchulbong summit access and comfort level can be affected by weather and crowd conditions","If a stop becomes unsafe or impractical, timing or stop order may be adjusted while preserving the East Jeju route logic"]},{"id":"wear","title":"What to Wear and Bring","preview":"Walking shoes, layers, and wind protection are the basics","content":["Comfortable walking shoes with good grip","A light jacket or windproof outer layer","Sun protection and a hat on clear days","Water bottle","A small umbrella or light rain layer if the forecast is mixed"]},{"id":"included","title":"What’s Included / Not Included","preview":"Guide, vehicle, fixed pickup, and standard sightseeing support","variant":"included","content":["Professional English-speaking guide","Shared bus transportation","Fixed pickup and drop-off in Jeju City","Basic guided sightseeing support","Admission fees are not included unless otherwise specified at checkout","Lunch is not included unless otherwise specified","Personal expenses, café purchases, and optional shopping are not included","Guide gratuities are optional"]}],"bookingTrustItems":[{"icon":"check-circle","title":"Fixed Jeju City pickups","description":"Four meeting points with scheduled times","iconBg":"bg-emerald-50/80","iconColor":"text-emerald-600"},{"icon":"route","title":"Structured bus day","description":"Clear stop order and return window","iconBg":"bg-sky-50/80","iconColor":"text-sky-600"},{"icon":"users","title":"Full East Jeju coverage","description":"Iconic sights at a bus-tour price point","iconBg":"bg-amber-50/80","iconColor":"text-amber-600"}],"bookingSupportSteps":[{"timing":"예약 시 (중요)","title":"실제로 확인하는 연락처","detail":"예약 시 평소 쓰는 휴대폰 번호, 왓스앱 번호, 라인 ID 또는 친추 링크를 남겨 주세요. 연락이 닿지 않으면 전날 미팅 확인이 어려울 수 있습니다."},{"timing":"예약 직후","title":"예약 확정 메일","detail":"먼저 예약 확정 메일로 코스 요약, 금액, 픽업·미팅 방식이 안내됩니다."},{"timing":"투어 전날","title":"가이드가 직접 연락","detail":"출발 하루 전, 담당 가이드가 왓스앱·라인·전화로 직접 연락해 시간, 정확한 미팅 장소, 마지막 안내를 전해 드립니다."},{"timing":"투어 당일","title":"미팅 장소","detail":"안내된 시간보다 최소 10분 일찍 도착해 주세요. 버스는 정시 출발이며, 가이드가 알려 준 시간을 따릅니다."},{"timing":"투어 종료 후","title":"하차·문의","detail":"제주 시내 정해진 하차 지점에서 하차합니다. 이후 도움이 필요하면 메시지로 연락 주세요."}],"practicalWeatherStatic":{"today":{"temp":"—","label":"Live weather integration"},"tomorrow":{"temp":"—","label":"Updated daily"}},"seasonalVariations":[{"name":"Spring","icon":"flower","description":"Seongeup and Hamdeok usually feel lighter and more colorful. Visibility can make Seongsan particularly rewarding on clear days.","tag":"Mild weather","bgClass":"bg-spring","iconColor":"text-pink-500"},{"name":"Summer","icon":"sun","description":"Hamdeok becomes a stronger crowd-appeal stop. Heat and humidity make Seongsan feel more physically demanding, while Ilchul Land''s shaded caves gain value.","tag":"Lush scenery","bgClass":"bg-summer","iconColor":"text-yellow-500"},{"name":"Autumn","icon":"leaf","description":"Comfortable walking temperatures generally improve overall route feel. Clearer air can lift Seongsan and Hamdeok photo quality.","tag":"Best photo season","bgClass":"bg-autumn","iconColor":"text-orange-500"},{"name":"Winter","icon":"snowflake","description":"Wind exposure matters more at Seongsan, the haenyeo stop, and Hamdeok. The cultural stops become relatively more important for route comfort.","tag":"Weather-sensitive","bgClass":"bg-winter","iconColor":"text-sky-500"}],"faqItems":[{"q":"Is this a good East Jeju tour for first-time visitors?","a":"Yes. It covers several of East Jeju''s best-known highlights in one day and keeps the price lower than a private tour, which makes it a strong first-visit bus option."},{"q":"How difficult is the walking on this route?","a":"Most stops are manageable for average travelers. The one stop that clearly feels more active is Seongsan Ilchulbong, which includes stairs and uphill walking if you go toward the summit."},{"q":"What happens if the haenyeo show is cancelled?","a":"If sea or weather conditions prevent normal operation, the route should switch to Jeju Haenyeo Museum so the cultural logic of the day is preserved."},{"q":"Are admission tickets included?","a":"This JSON is structured for a bus-tour setup where admission is not included unless your checkout configuration says otherwise. Keep the live product setup aligned with your actual offer."}],"reviewsPreview":{"averageRating":4.8,"totalReviews":112,"highlights":[{"label":"Scenery","count":79},{"label":"Guide","count":51},{"label":"Culture","count":42},{"label":"Value","count":47}],"featured":[{"name":"Emma","country":"Australia","rating":5,"comment":"A very satisfying East Jeju route for first-time visitors. Seongsan was the big landmark, but the haenyeo story and Seongeup made the day feel richer than a scenery-only tour.","tripType":"Couple"},{"name":"Michael","country":"United States","rating":4,"comment":"Good value for a bus tour. The Seongsan climb was the hardest part, but the rest of the stops were well spaced and Hamdeok was a nice way to finish.","tripType":"Family"}]},"stickyBooking":{"price":{"amountLabel":"49","currency":"USD","per":"person"}},"matching_profile":{"product_id":"east-jeju-classic-bus-tour","product_type":"bus","route_type":"fixed_route","region_type":"east","region_tags":["jeju_east","seongsan","pyoseon","hamdeok"],"theme_tags":["unesco","folk_village","haenyeo","beach","lava_cave","first_time_friendly","iconic_landmarks","value_route"],"poi_tags":["ilchul_land","seongeup_folk_village","seongsan_ilchulbong","haenyeo_show","hamdeok_beach"],"pace_level":4,"walking_level":3,"scenic_level":5,"photo_level":5,"culture_level":4,"relax_level":3,"first_time_fit":5,"family_fit":4,"senior_fit":3,"couple_fit":5,"active_traveler_fit":4,"one_day_fit":4,"same_day_flight_fit":2,"rain_fit":3,"value_for_money_fit":5,"iconic_landmark_fit":5,"cafe_fit":3,"adult_family_fit":4,"young_kids_fit":3,"senior_active_fit":4,"senior_general_fit":3,"mobility_friendly_fit":2,"stroller_fit":2,"indoor_ratio":32,"weather_sensitivity":3,"local_culture_fit":4,"shopping_fit":2,"storytelling_fit":5,"comfort_level":3,"budget_fit":5,"premium_fit":1,"small_group_fit":1,"private_fit":1,"bus_fit":5,"price_band":"budget","pickup_base":"jeju_city","return_time_band":"17:40-18:20","duration_band":"9h","min_recommended_age":7,"hard_constraints":{"avoidIf":["high_wind_or_rough_sea_alert_on_east_coast","travelers_needing_a_slow_luxury_pace"],"notIdealFor":["very_low_mobility","stroller_heavy_on_steps_or_slopes","travelers_avoiding_stairs"]},"walking_notes":["Overall walking is moderate for a bus tour rather than a hiking tour.","Ilchul Land, Seongeup, the haenyeo stop, and Hamdeok are manageable for most travelers.","Seongsan Ilchulbong is the steepest and most physically demanding stop because of stairs and uphill sections.","Comfortable grip shoes are strongly recommended, especially in wet or windy weather."],"keywords":["east jeju bus tour","seongsan ilchulbong hamdeok day tour","jeju folk village and haenyeo tour","ilchul land east jeju tour","best value east jeju bus tour","first time east jeju day trip","hamdeok beach bus day tour","seongeup village seongsan bus tour","jeju haenyeo culture day tour","classic east jeju route"],"synonym_hints":["classic east jeju bus route","east jeju highlights by bus","seongsan hamdeok folk village day","budget-friendly east jeju tour","unesco and beach east jeju day","fixed pickup jeju bus tour"],"profile_version":1,"is_active":true},"matching_metadata":{"matching_schema":"tour_matching_profiles_embedded_v1","embedded_for":["authoring","review","sql_backfill_reference"],"note":"Scores were tuned for a classic East Jeju bus-tour format: very high iconic and storytelling fit, moderate walking overall, and moderate rain resilience because Ilchul Land adds indoor-outdoor balance and the haenyeo stop has a museum fallback, while Seongsan and Hamdeok remain weather-sensitive."},"pickup_dropoff":{"pickupType":"fixed_meeting_points","dropoffType":"fixed_dropoff_points","departure":[{"order":1,"time":"08:30","name":"Ocean Suites Hotel","type":"hotel","note":"Main city pickup point near Tapdong."},{"order":2,"time":"08:45","name":"Jeju Airport, 3rd Floor Gate 3","type":"airport","note":"Departure floor meeting point."},{"order":3,"time":"08:55","name":"Lotte City Hotel Jeju","type":"hotel","note":"Central Jeju City hotel pickup point."},{"order":4,"time":"09:05","name":"Shilla Duty Free Shop","type":"shopping","note":"Popular downtown meeting point."}],"return":[{"order":1,"name":"Ocean Suites Hotel","type":"hotel","note":"Standard city drop-off point."},{"order":2,"name":"Jeju Airport, 3rd Floor Gate 3","type":"airport","note":"Useful for same-day departures; exact stop order may vary."},{"order":3,"name":"Lotte City Hotel Jeju","type":"hotel","note":"Standard city drop-off point."},{"order":4,"name":"Shilla Duty Free Shop","type":"shopping","note":"Standard city drop-off point."},{"order":5,"name":"Dongmun Market","type":"market","note":"Additional downtown drop-off for travelers who want to continue the evening in central Jeju City."}],"notes":["Return usually runs around 17:40–18:20 depending on traffic, weather, and whether the haenyeo show operates normally.","Drop-off order may be adjusted slightly for operational efficiency.","Please arrive at least 10 minutes early at your selected pickup point."]}}'::jsonb
