  '{"document_kind":"tour_product_full_page_v1","schema_version":1,"slug":"east-jeju-classic-bus-tour","locale":"ja","product_id":"east-jeju-classic-bus-tour","seo":{"pageTitle":"East Jeju Sunrise Peak, Folk Village & Hamdeok Bus Day Tour | AtoC Korea","metaDescription":"A classic East Jeju bus day tour covering Ilchul Land, Seongeup Folk Village, Seongsan Ilchulbong, the Haenyeo Show, and Hamdeok Beach. A strong first-time route for travelers who want Jeju’s iconic east-side nature and culture in one day."},"catalog_card":{"slug":"east-jeju-classic-bus-tour","title":"East Jeju Sunrise Peak, Folk Village & Hamdeok Bus Day Tour","subtitle":"Lava cave atmosphere, living village culture, UNESCO scenery, haenyeo heritage, and a signature beach in one classic east-side route, now with one hour of free lunch time near Seongsan.","region":"East Jeju","duration":"10 hours","stopsCount":6,"rating":4.8,"reviewCount":112,"badges":["Best-Value Bus Tour","Classic East Jeju Route","First-Time Friendly"],"heroImage":"https://api.cdn.visitjeju.net/photomng/imgpath/202409/20/c8bf6191-832c-4605-a948-96f07f6112d2.webp","thumbnail":"https://api.cdn.visitjeju.net/photomng/thumbnailpath/202409/20/b9661064-af2f-4197-aef0-d3d44bf6c2b5.webp","priceLabel":"From US$49 per person","shortCardDescription":"A full-day East Jeju bus route that links cave scenery, traditional village culture, Seongsan Ilchulbong, living haenyeo heritage, and Hamdeok Beach, with one hour of free lunch time added near Seongsan. It is built for travelers who want strong iconic coverage with a lower price barrier."},"headlineLine1":"East Jeju Sunrise Peak, Folk Village","headlineLine2":"and Hamdeok Bus Day Tour","price":{"amountLabel":"49","currency":"USD","per":"person"},"hero":{"imageUrl":"https://api.cdn.visitjeju.net/photomng/imgpath/202409/20/c8bf6191-832c-4605-a948-96f07f6112d2.webp","imagePosition":"center 52%","tagline":"From lava-cave atmosphere and a living folk village to UNESCO coastal scenery, Jeju haenyeo culture, and Hamdeok’s clear water, this classic East Jeju bus route delivers iconic variety at a practical price point, with one hour of free lunch time included near Seongsan.","pills":["Classic East Jeju","Bus Day Tour","Best Value"],"meta":{"duration":"10 hours","region":"East Jeju","stops":"6 stops","rating":4.8,"ratingStars":5}},"subnavItems":[{"id":"overview","label":"Overview"},{"id":"itinerary","label":"Itinerary"},{"id":"details","label":"Details"},{"id":"faq","label":"FAQ"},{"id":"reviews","label":"Reviews"}],"glanceItems":[{"icon":"camera","label":"Photo Potential","value":"Very High"},{"icon":"mountain","label":"Scenery Density","value":"High"},{"icon":"footprints","label":"Walking Difficulty","value":"Moderate"},{"icon":"cloud-rain","label":"Rain Suitability","value":"Moderate"},{"icon":"users","label":"Family Suitability","value":"Good"},{"icon":"gauge","label":"Pace","value":"Full but Comfortable"}],"galleryItems":[{"id":1,"type":"photo","src":"https://api.cdn.visitjeju.net/photomng/imgpath/202409/20/c8bf6191-832c-4605-a948-96f07f6112d2.webp","location":"Seongsan Ilchulbong","atmosphere":"The day''s signature UNESCO landmark and strongest iconic view","alt":"Seongsan Ilchulbong rising above the East Jeju coast"},{"id":2,"type":"photo","src":"https://api.cdn.visitjeju.net/photomng/imgpath/202207/14/47bdc32f-cb51-4de3-8239-06299643b485.webp","location":"Ilchul Land / Micheongul Cave","atmosphere":"A cooler lava-cave opening with indoor value and unusual texture","alt":"Micheongul Cave inside Ilchul Land in East Jeju"},{"id":3,"type":"photo","src":"https://api.cdn.visitjeju.net/photomng/imgpath/202409/06/cf7e9f6b-178f-4d3d-b978-91beb5145a10.webp","location":"Seongeup Folk Village","atmosphere":"Living heritage and old Jeju village character","alt":"Traditional houses at Seongeup Folk Village in Jeju"},{"id":4,"type":"photo","src":"https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=1200&q=80","location":"Hamdeok Beach","atmosphere":"A bright, relaxed finish with Jeju''s signature clear water feeling","alt":"Bright coastal atmosphere inspired by Hamdeok Beach in Jeju"}],"itineraryStops":[{"number":1,"time":"09:50","duration":"60 min","name":"Ilchul Land","category":"Garden and Lava Cave Stop","description":"Ilchul Land works well as an opening stop because it combines easy garden circulation with the cooler Micheongul lava-cave section. It gives the day an early indoor-outdoor balance before the route moves deeper into East Jeju''s cultural and coastal landmarks.","image":"https://api.cdn.visitjeju.net/photomng/imgpath/202207/14/47bdc32f-cb51-4de3-8239-06299643b485.webp","highlights":["A flexible first stop with both outdoor paths and cave atmosphere","Useful early rain-buffer compared with a fully exposed route opening","Good variety for mixed-age groups","A different visual tone from the coast-heavy second half"],"timeUsed":["Arrival briefing and entry","Garden walk and Micheongul cave viewing","Regroup and depart"],"whyOnRoute":"Starting here gives the route a softer operational opening and improves weather resilience before the village, UNESCO climb, and exposed coastline sections.","visitBasics":{"hours":"08:30–19:00 / Micheongul cave admission generally until 1 hour before sunset","closed":"Open year-round","admission":"Commonly ticketed attraction; keep live pricing aligned with current checkout setup","walking":"Easy"},"convenience":{"restroom":"Available on site","parking":"Parking available"},"smartNotes":{"photo":"The cave textures and garden framing work better than rushed single-point photos, so this stop benefits from steady pacing.","facilities":"Facilities are stronger here than at most pure viewpoint stops.","tip":"This is one of the route''s best buffers when wind or light rain makes later outdoor stops less comfortable."}},{"number":2,"time":"11:05","duration":"40 min","name":"Seongeup Folk Village","category":"Living Heritage Village","description":"Seongeup adds cultural depth that many scenic-only routes miss. Because it is a living village rather than a staged set, the stop gives travelers a clearer sense of old Jeju homes, stone walls, and daily life traditions.","image":"https://api.cdn.visitjeju.net/photomng/imgpath/202409/06/cf7e9f6b-178f-4d3d-b978-91beb5145a10.webp","highlights":["One of East Jeju''s strongest culture-focused stops","A living village with real local heritage value","Adds storytelling depth between nature landmarks","Works well for first-time visitors who want more than scenery alone"],"timeUsed":["Village orientation and short guided walk","Free look-around and photo time","Regroup and depart"],"whyOnRoute":"It breaks up the nature-heavy flow and adds heritage context before the route turns toward Seongsan and the coast.","visitBasics":{"hours":"Open village environment; access patterns can vary by site area and local operation","closed":"Open year-round","admission":"Generally free to enter the village area, though some shops or experiences may be optional","walking":"Easy to moderate"},"convenience":{"restroom":"Available in or near visitor areas","parking":"Parking available"},"smartNotes":{"photo":"Stone walls, thatched roofs, and side-lane composition usually read better than wide rushed overview shots.","facilities":"This is a cultural walk stop rather than a large modern complex.","tip":"Keep the stop focused on village character and guide context rather than overextending shopping time."}},{"number":3,"time":"12:10","duration":"70 min","name":"Seongsan Ilchulbong","category":"UNESCO Tuff Cone Landmark","description":"Seongsan Ilchulbong is the route''s most iconic landmark and one of Jeju''s strongest first-time stops. The summit trail is short in distance but clearly steep, so the stop feels more active than most bus-tour landmarks.","image":"https://api.cdn.visitjeju.net/photomng/imgpath/202409/20/c8bf6191-832c-4605-a948-96f07f6112d2.webp","highlights":["UNESCO World Natural Heritage site and one of Jeju''s signature views","High payoff for first-time visitors","Short but steep summit climb with strong visual reward","A landmark that anchors the whole route"],"timeUsed":["Entry and trail briefing","Ascent or lower-area sightseeing depending on pace and condition","Regroup and depart"],"whyOnRoute":"This is the natural centerpiece of an East Jeju classic route, so it works best near midday when visibility is often still stable and the day''s momentum is high.","visitBasics":{"hours":"Seasonal operation; for example, Nov–Feb 00:00–18:00, Mar–Apr & Sep–Oct 05:00–19:00, May–Aug 04:30–20:00, with ticketing ending earlier","closed":"First Monday of each month, or the following day if Monday is a public holiday","admission":"Ticketed summit section; keep live pricing aligned with current checkout setup","walking":"Moderate to difficult if climbing to the top"},"convenience":{"restroom":"Available near the entrance area","parking":"Parking available"},"smartNotes":{"photo":"Wide crater-and-sea framing is usually the strongest visual payoff.","facilities":"This is a major landmark stop with solid basic visitor support.","tip":"Not every traveler needs to do the full summit climb; the lower-area coastal section can still work for guests avoiding heavier stairs."}},{"number":4,"time":"13:25","duration":"60 min","name":"Lunch Break (Free Choice)","category":"Meal break","description":"Enjoy one hour of free lunch time near Seongsan. This flexible meal break lets travelers choose a restaurant that fits their taste and pace before continuing to the haenyeo segment.","image":"https://images.unsplash.com/photo-1551218808-94e220e084d2?w=1200&q=80&fm=jpg","highlights":["One full hour for lunch","Free-choice meal stop","Placed after Seongsan climbing time","Better pacing before the afternoon program"],"timeUsed":["Lunch","Restroom break","Seat reset before departure"],"whyOnRoute":"This break sits naturally after the Seongsan stop, where many travelers want time to recover from the climb and eat before the afternoon coastal segment.","visitBasics":{"hours":"Depends on restaurant","closed":"Varies by venue","admission":"Meal cost not included","walking":"Low"},"convenience":{"restroom":"Available at nearby restaurants","parking":"Bus-accessible nearby"},"smartNotes":{"photo":"Not a photo-focused stop","facilities":"Restaurant options vary by day and traffic flow","tip":"A simple local meal works best if you want a relaxed pace."}},{"number":5,"time":"15:00","duration":"40 min","name":"Haenyeo Show","category":"Living Coastal Culture Performance","description":"The haenyeo stop adds something few Jeju routes can match: living culture happening on the coast rather than inside a display panel. Because the performance is weather-sensitive, the tour should treat it as a priority highlight with a clear fallback plan.","image":"https://images.unsplash.com/photo-1544551763-46a013bb70d5?w=1200&q=80","highlights":["One of the best ways to connect Jeju sightseeing with living local culture","Stronger storytelling value than a standard photo stop","Directly tied to Jeju''s haenyeo heritage","Memorable when sea conditions allow normal operation"],"timeUsed":["Move to the viewing area and guide context","Observe the performance if operating normally","If cancelled for weather, replace with Jeju Haenyeo Museum"],"whyOnRoute":"Positioning this after Seongsan keeps the coastal storytelling connected and makes the cultural flow feel natural rather than inserted.","visitBasics":{"hours":"Planned around the 14:00 show window on this product; actual operation is subject to season and weather conditions","closed":"May be cancelled or adjusted in rough sea or poor weather","admission":"Usually viewed without a major ticket barrier, but keep live setup aligned with operations","walking":"Easy"},"convenience":{"restroom":"Basic facilities vary by viewing point and nearby shops","parking":"Operational drop-off and parking depend on day-of traffic"},"smartNotes":{"photo":"Use wider framing and avoid expecting a perfectly fixed stage environment.","facilities":"This is a live coastal viewing stop, so comfort is more weather-dependent than at museums or indoor sites.","tip":"If the show is cancelled, the Jeju Haenyeo Museum is the cleanest substitution because it preserves the route''s cultural logic."}},{"number":6,"time":"16:25","duration":"45 min","name":"Hamdeok Beach","category":"Signature Beach Walk","description":"Hamdeok gives the day a bright, easy finish. After the more structured stops at Seongeup, Seongsan, and the haenyeo segment, the white sand and clear water create a simpler closing mood that many travelers find refreshing.","image":"https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=1200&q=80","highlights":["One of Jeju''s best-known beaches","Clear water and easy seafront walking","A relaxed visual finish after a fuller sightseeing day","Good family and couple appeal"],"timeUsed":["Beachfront orientation and free walk","Photos and short break time","Regroup for return to Jeju City"],"whyOnRoute":"It works naturally as a late-day decompression stop before the return drive to Jeju City.","visitBasics":{"hours":"Open 24 hours","closed":"Open year-round","admission":"Free","walking":"Easy"},"convenience":{"restroom":"Available in the beach area","parking":"Parking available nearby"},"smartNotes":{"photo":"The water color reads best in wider beach shots and side angles rather than tight front-on framing.","facilities":"Amenities and surrounding cafés are part of why this stop feels easy and finish-friendly.","tip":"In strong wind or rough weather, reduce expectations for a long beach stay and keep the stop focused."}}],"routeFlowStops":[{"id":"ilchul-land","name":"Ilchul Land","theme":"Cave + garden opening"},{"id":"seongeup","name":"Seongeup Folk Village","theme":"Living heritage"},{"id":"seongsan","name":"Seongsan Ilchulbong","theme":"UNESCO landmark"},{"id":"lunch-seongsan","name":"Lunch Break (Free Choice)","the